---从web获取活动配置数据
function ModelActivity:GetWebActivityDataById(sid)
    local data = self:GetActivityBySid(sid)
    if not data then
        return
    end
    local webData = self._webActivityDataList[sid]

    if not webData or webData:IsDestroy() then
        webData = LActivityWebData:New()
        self._webActivityDataList[sid] = webData
        webData:InitFirstData(sid, data.verifyTime)

        if LOG_INFO_ENABLED then
            printInfoN2("cjh-----------活动activedata 创建", "-------------1---GetWebActivityDataById")
        end

        if (webData:StartInitWebData()) then
            return webData:GetData()
        end
        return
    end

    if webData:IsReqing() then
        return
    end

    if (webData:IsOutOfDate(data.verifyTime)) then
        webData:SetVerifyTime(data.verifyTime)
        if (webData:StartInitWebData()) then
            return webData:GetData()
        end
        return
    end

    return webData:GetData()
end

function ModelActivity:GetWebActivityPageData(sid, pageId)
    local webData = self._webActivityDataList[sid]
    if not webData or webData:IsDestroy() then
        return
    end
    return webData:GetPage(pageId)
end

function ModelActivity:GetWebActivityEntryData(sid, pageId, entryId)
    local webData = self._webActivityDataList[sid]
    if not webData or webData:IsDestroy() then
        return
    end

    return webData:GetEntry(pageId, entryId)
end

function ModelActivity:ReqActivityConfigData(sid)
    local data = self:GetWebActivityDataById(sid)
    if data then
        FireEvent(EventNames.ON_ACTIVITY_CONFIG_DATA, data, sid)
    end
end
