function ModelActivity:OnActivityReceiveGoalListReq(list)
    --sid,pageId,entryId
    local pb = LProtoHelper.CreateProto(LProtoIds.ActivityReceiveGoalListReq)
    local goalEntries = pb.goalEntries
    for k, v in ipairs(list) do
        local goalEntry = goalEntries:add()
