-- 活动特殊操作
function ModelActivity:OnActivitySpecialOpReq(sid, pageId, entryId, opType, args, type)
    local pb = LProtoHelper.CreateProto(LProtoIds.ActivitySpecialOpReq)
    pb.sid = sid

    if type == 26 then
        local model = self:GetActivityModeIdBySid(sid)

        local canSend = self._canClickCancelModelRedpoint[model]

        if not canSend then
            if LOG_INFO_ENABLED then
                printInfoN2("活动点击红点---未在_canClickCancelModelRedpoint注册--", "sid-" .. sid .. "--model--" .. model)
            end
            return
        end
    end

    if pageId then
        pb.pageId = pageId
    end
    if entryId then
        pb.entryId = entryId
    end

    if not type then
        --1-一键领取奖励(模板1),2-领取免费礼包奖励(模板4),3-领取购买10天条目奖励(模板4),
        --4-随机专属折扣(模板31), 5-修补童话书 ,6-魔女秘语, 12-轮次活动去掉分页红点
        pb.opType = opType or 1
    end

    if args then
        --当opType = 6时: 1=p1|p2|... or 2=pIndex|cIndex or 3【1=解梦操作、p=输入的密码; 2=消除噩梦卡、pIndex=密码所在下标（1-N）、cIndex=掀开的噩梦卡下标（1=6）; 3 = 重置卡牌密码与状态】
        pb.args = args
    end

    --后续加请求类型，都用这个type枚举，不再使用opType
    if type then
        pb.type = type
    end

    SendMessage(pb, LProtoIds.ActivitySpecialOpReq)

    if type and self:CheckIsNeedProtect(sid, type) then
        self:SetActivityCallProtect(false)
    end
end

-- 购买商品分页的商品条目
