        [ModelActivity.MODEL_ACTIVITY_TYPE_34] = true,
    }

    local model13Id = ModelActivity.MODEL_PASSB

    local hasEnterMain = gModelGeneral:GetHasEnteredCityMap()

    for k, v in ipairs(pb.activities) do
        local activity = StructActivity:New()
