        if not changeModelMap[model] then
            changeModelMap[model] = true
            table.insert(changeModelList, model)
        end

        if activity.status ~= 3 then
            if reqActivityConfigList[model] then
                self:ReqActivityConfigData(activity.sid)
            end

            if model13Id == model then
                self:StartInitModel13Config(activity.sid)
            end
            -- if model == ModelActivity.NEW_HERO_THEME_B then
            --     self:TryInsertNewHeroThemeBWnd(activity.sid)
            -- elseif model == ModelActivity.NEW_HERO_THEME_A then
            --     self:TryInsertNewHeroThemeAWnd(activity.sid)
