            -- if model == ModelActivity.SUMMER_DAY then
            --     self:InsertBandThemeRain(activity)
            -- if model == ModelActivity.FAIRY_FATHER_DAY then
            --     self:InsertNewYear2022Rain(activity)
            if model == ModelActivity.ADVERTISING_PHOTO then
                self:InsertAdvertisingPhotoPopWnd(activity)
                -- elseif model == ModelActivity.ACTIVITY_PAINTED_EGG then
                --     self:InsertPaintedEggCollNumReward(activity)
            elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_63 then
                isOpenDownLoadAct = true
            elseif model == ModelActivity.ANNIVERSARY_DAILY_KOI_83 then
                --每日锦鲤活动弹框

                -- elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_84 then
                --     self:SaveModel84CfgInfo(activity)
                -- elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_86 then
                --     self:TryInsertAnniversarySummary(activity)
            elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_102 then
                --GF.OpenWnd("UIHuiYService", { sid = activity.sid })
                --printInfoNR("......MODEL_ACTIVITY_TYPE_102.......")
                -- elseif model == ModelActivity.MODEL_TREASURE_HOT then
                --     self:InsertTreaHotWnd(activity)
            elseif model == ModelActivity.DISCOUNTS_SKIN then
                --local moreInfo = activity.moreInfo
                --local info = JSON.decode(moreInfo)
                local info = activity:GetMoreInfo()
                local popControl = info.popControl
                local buyAll = info.buyAll or 0
                if popControl == 1 and buyAll ~= 1 then
                    self:InsertDiscountsSkinWnd(activity)
                end
                -- elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_121 then
                --     local sid = activity.sid
                --     gModelFairCompete:OnFairCompeteDataInfoReq(sid)
                --     gModelFairCompete:OnFairCompeteGetFormationReq(sid)
            elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_105 then
                self:InitNewHeroThemePop(activity.sid)

            elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_151 then
                --local moreInfo = activity.moreInfo
                --local info = JSON.decode(moreInfo)
                local info = activity:GetMoreInfo()
                local costItem = info.costNum
                local costs = string.split(costItem, '|')
                local tempItemData = string.split(costs[1], '=')
                local itemRefId = tonumber(tempItemData[2])

                if not self._CheckItemRefreshList then
                    self._CheckItemRefreshList = {}
                end

                if not self._CheckItemRefreshList[itemRefId] then
                    self._CheckItemRefreshList[itemRefId] = {}
                end

                table.insert(self._CheckItemRefreshList[itemRefId], activity.sid)
            elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_34 then
                self:CheckIsShowModel34(v)
            end
            if _redModels[model] then
                table.insert(_redRecordSids, activity.sid)
            end
        end
        if (model == ModelActivity.MODEL_ACTIVITY_TYPE_93) then
            local modelActiveData = self:GetWebActivityDataById(activity.sid)
            local isCanInsert = false
            local packKey
            if modelActiveData then
                packKey = modelActiveData.config.packId
            else
                packKey = activity.packId
            end

            if nil == packKey then
                isCanInsert = true
            end

            if not isCanInsert then
                local checkPack = checknumber(LGameSettings.platformId)
                packKey = string.split(packKey, ";")

                for k, v in ipairs(packKey) do
                    if checknumber(v) == checkPack then
                        isCanInsert = true
                        break
                    end
                end
            end
            if isCanInsert then
                table.insert(model93List, activity)
            end
        end
    end
    if (model93List and #model93List > 0) then
        self:SetActivityPopupList(model93List)
    end
    self._activityListByType = {}
    self._activityListByModel = {}

    local _activityListById = self:GetActivityListById()
    for k, v in pairs(_activityListById) do
