        self:CheckIsDownLoadFinish()
    end

    self:InsertNewEightLoginWnd()

    self:TryInsertActivityGuide(needGuideSidList)

    FireEvent(EventNames.ON_ACTIVITY_MODELCHANGE, changeModelList)
    FireEvent(EventNames.ON_ACTIVITY_LIST_CHANGE)

    self:LogActivityInfo()
end

function ModelActivity:LogActivityInfo()
    if LOG_INFO_ENABLED then
        if (self._activityListById) then
            local list = {}
            for k, v in pairs(self._activityListById) do

                local str = string.format("sid:%s,model %s,status:%s", k, v.model, v.status)
                table.insert(list, str)
            end

            printInfoN(table.concat(list, "\n"))
        end
    end
end

function ModelActivity:GetMainEntranceActivityList()
    local list = {}
    local curTime = GetTimestamp()
    for k, v in pairs(self._activityListById) do
        if v.showScene == 3 then
            if self:CheckShowPackId(v) then
                if v.startTime > 0 then
                    if v.startTime < curTime and curTime < v.showEndTime then
                        table.insert(list, v)
                    end
                else
                    table.insert(list, v)
                end
            end
        end
    end

    return list
end

---@param activity StructActivity
function ModelActivity:CheckShowPackId(activity)
    if not activity then return false end
    if activity.model == ModelActivity.MODEL_ACTIVITY_TYPE_85 then
        local packageId = self:GetPackageId()
        local packId = activity.packId
        if not string.isempty(packId) then
            packId = string.split(packId,";")
            for idx,val in ipairs(packId) do
                val = checknumber(val)
                if packageId == val then
                    return false
                end
            end
            return true
        end
    elseif activity.model == ModelActivity.MODEL_ACTIVITY_TYPE_102 then
        return self:IsHasPackId(activity.packId)
    end
    return true
end

---@param activity StructActivity
function ModelActivity:RecordUniqueJump(activity)
    if not self._jumpMap then
        self._jumpMap = {}
    end
    --local moreInfo = JSON.decode(activity.moreInfo)
    local moreInfo = activity:GetMoreInfo()
    if moreInfo then
        if activity.status ~= 3 then
            local jumpId = tonumber(moreInfo.uniqueJump)
            if jumpId then
                self._jumpMap[jumpId] = activity.sid
            else
                jumpId = activity.uniqueJump
                if jumpId and jumpId > 0 and not self._jumpMap[jumpId] then
                    self._jumpMap[jumpId] = activity.sid
                end
            end
        end
    end
end

function ModelActivity:OnActivityResp(pb, ret)
    local _redModels = self._redModels or {}
    local _redRecordSids = {}
    local data = pb.activity
    local sid, model = data.sid, data.model
    local activity = StructActivity:New()
    activity:CreateByPb(data)
    if _redModels[activity.model] then
        table.insert(_redRecordSids, activity.sid)
    end

    self._activityListById[sid] = activity
    self._activityListByType = {}
    self._activityListByModel = {}
    local _activityListById = self:GetActivityListById()
    for k, v in pairs(_activityListById) do
        local type = v.type
        local typeList = self._activityListByType[type]
        if not typeList then
            typeList = {}
            self._activityListByType[type] = typeList
        end
        table.insert(typeList, v)

        local model = v.model
        local modelList = self._activityListByModel[model]
        if not modelList then
            modelList = {}
            self._activityListByModel[model] = modelList
        end

        table.insert(modelList, v)
        -- if model == ModelActivity.MODEL_CHN_CELEBRATE then
        --     self:SetSupperzzleStatus(false)
        -- end
    end

    self:RecordUniqueJump(activity)
    if #_redRecordSids > 0 then
        self:SaveRedSids(_redRecordSids)
    end
    FireEvent(EventNames.ON_ACTIVITY_MODELCHANGE, { model })
    --FireEvent(EventNames.ON_ACTIVITY_CHANGE)
    FireEvent(EventNames.ON_ACTIVITY_LIST_CHANGE)

    self:LogActivityInfo()

end

function ModelActivity:OnActivityPageResp(pb, ret)
    --local sid = pb.sid
    --self._activityPageMap[sid] = pb
    local sid = pb.sid
    local modelId = self:GetActivityModeIdBySid(sid)
    --新伙伴专题A，B，登录打开每日签到界面
    local pageList = {}
    if sid == self._needReqNewHeroThemeBSid then
        self:InsertNewHeroThemeBWnd(pb)
    elseif sid == self._needReqNewHeroThemeASid then
        self:InsertNewHeroThemeAWnd(pb)
    else
        if modelId == ModelActivity.MODEL_ACTIVITY_TYPE_74 or
                modelId == ModelActivity.MODEL_ACTIVITY_TYPE_153 or
                -- modelId == ModelActivity.MODEL_ACTIVITY_TYPE_167 or
                modelId == ModelActivity.MODEL_ACTIVITY_TYPE_168 then
            local _activityPageKeyList = self._activityPageKeyList or {}
            local _activityPageList = _activityPageKeyList[sid] or {}
            for i, v in ipairs(pb.pages) do
                local page = self:GenerateActivePageDataFromPb(v)
                pageList[page.pageId] = page
                _activityPageList[page.pageId] = page
            end
            _activityPageKeyList[sid] = _activityPageList
            self._activityPageKeyList = _activityPageKeyList
        end
    end

    if modelId == ModelActivity.MODEL_ACTIVITY_TYPE_74 then
        self:UpdateOnlineRewardData(sid)
    end

    if modelId == ModelActivity.EXCHANGE then
        printInfoN2("--", "--")
    end

    if self:CheckIsModel13ReqPage(sid) then
        self:OnModel13PageDataResp(sid,pb.pages)
    end

    FireEvent(EventNames.ON_ACTIVITY_PAGE_CHANGE, modelId, sid, pb.pages)
end

function ModelActivity:GetActivityPagesBySid(sid, pageId)
    local _activityPageKeyList = self._activityPageKeyList or {}
    local _activityPageList = _activityPageKeyList[sid]
    if not _activityPageList then
        return
    end
    return _activityPageList[pageId]
end
function ModelActivity:GetActivityPagesListBySid(sid)
    local _activityPageKeyList = self._activityPageKeyList or {}
    local _activityPageList = _activityPageKeyList[sid]
    return _activityPageList
end

