-- 活动   sid|createTime|key:type=refId=num,type=refId=num;key:type=refId=num,type=refId=num;
function ModelActivity:CombinationStr(sid, createTime, num, name, data)
    --local str = ""
    local strList = {}
    for k, v in pairs(data) do
        table.insert(strList, tostring(k))
        table.insert(strList, ':')
        table.insert(strList, tostring(v))

        --local tempStr = k .. ":" .. v
        --if string.isempty(str) then
        --    str = tempStr
        --else
        --    str = str .. ";" ..tempStr
        --end
    end
    local str = table.concat(strList, ';')
    str = string.format("%s|%s|%s|%s|%s", sid, createTime, num, name, str) -- sid .. "|" .. createTime .. "|" .. num .. "|"  .. name .. "|"  .. str
    return str
end

function ModelActivity:SaveActivityCallLog(sid, createTime, num, name, data)
    local logStr = self:CombinationStr(sid, createTime, num, name, data)
    local activityCallHeroLog = LPlayerPrefs.activityCallHeroLog
    local addStr
    if string.isempty(activityCallHeroLog) then
        addStr = logStr
    else
        addStr = activityCallHeroLog .. "-" .. logStr
    end
    LPlayerPrefs.SetActivityCallHeroLog(addStr)
end

