            unlockProtectFunc()
            return
        end
        if lotteryBModelList[model] then
            FireEvent(EventNames.ON_ACTIVITY_MOTIFLOTTERYB_CALL, para)
            unlockProtectFunc()
            return
        end

        GF.OpenWndTop("UIYellSagaAward", para)
    end
    unlockProtectFunc()
end

