    end

    local codeValue = tonumber(code)
    local isSuccess = 1
    if codeValue and codeValue == 0 then
        GF.ShowMessage(ccClientText(36912))
        isSuccess = 0
    end

    local playTime = GetTimestamp() - entryData.startTime

    --数数打点
    local TAData = {
        ["ad_refid"] = tostring(entryData.entryId),
        ["ad_addr"] = tostring(entryData.address),
