function ModelActivity:OnActivityFigurePositionUpdateResp(pb)
    local model = pb.model                  --活动模板
    local sum = pb.sum                      --当前进入场景的所有玩家数量
    local refreshType = pb.refreshType      --刷新类型:0=所有;1=增加;2=更新;3=移除
    local infos = pb.infos                  --列表数据

    local _activityPositionInfos = self._activityPositionInfos
    if not _activityPositionInfos then
        _activityPositionInfos = {}
    end
    local _infos = _activityPositionInfos[model] or {}
    if refreshType == ModelActivity.ACTIVITY_REFRESHTYPE_0 then
        _infos = {}
    end
    if refreshType ~= ModelActivity.ACTIVITY_REFRESHTYPE_3 then
        for i, v in ipairs(infos) do
            local info = self:GenerateStructActivityVillainPositionInfoDataFromPb(v)
            _infos[v.pid] = info
        end
    else
        for i, v in ipairs(infos) do
            _infos[v.pid] = nil
        end
    end

    _activityPositionInfos[model] = _infos
    self._activityPositionInfos = _activityPositionInfos
    self._sumList[model] = sum
end

