function ModelActivity:OnActivityMagicAcademyAnswerRoomResp(pb)
    --[[
        /**成员数据*/
        repeated AnswerRoomMember members = 1;
        /**当前所处阶段（ 1=预备答题，2=答题中，3=结束）*/
        required int32 stage = 2;
        /**当前答题轮次*/
        required int32 rounds = 3;
        /**当前阶段结束时刻（毫秒）*/
        required int64 endTime = 4;
        /**问题refId*/
        required int32 questionRefId = 5;
        /**房间号*/
        required string roomId = 6;
    ]]--
    local sid = pb.sid
    local members = pb.members
    local stage = pb.stage
    local roomId = pb.roomId
    local _members = {}
    for i, v in ipairs(members) do
        local info = self:GenerateStructAnswerRoomMemberDataFromPb(v)
        table.insert(_members, info)
    end
    local _answerRoomList = self._answerRoomList or {}
    local para = {
        sid = sid,
        members = _members,
        stage = stage,
        rounds = pb.rounds,
        endTime = pb.endTime,
        questionRefId = pb.questionRefId,
        roomId = roomId
    }
    _answerRoomList[sid] = para
    self._answerRoomList = _answerRoomList
    local isWeed = self:GetAnswerIsRoom(sid)
    if not isWeed then
        return
    end
    local _roomList = self._roomList or {}
    local roomName = "UIActKeyRoom"
    local mainName = "UIActKeyMin"
    if not GF.FindFirstWndByName(roomName) and not _roomList[roomId] then
        _roomList[roomId] = true
        self._roomList = _roomList
        --GF.OpenWnd(roomName,{sid = sid})
        local openFunc = function()
            local bool = gModelActivity:GetAnswerIsRoom(sid)
            if bool then
                if GF.FindFirstWndByName(mainName) then
                    GF.CloseWndByName(mainName)
                end
            end
        end

        if GF.FindFirstWndByName(mainName) then
            GF.OpenWnd("UIActKeyRoom", { sid = sid, openFunc = openFunc })
        else
            gModelWndPop:TryOpenPopWnd(roomName, { sid = sid, openFunc = openFunc })
        end
    end
end

