function ModelActivity:GetActivityIdByType(type)
    local idList = {}
    local netList = nil
    if self._activityListByType then
        netList = self._activityListByType[type]
    end
    local isIos = CS.IsOSIos()
    if netList then
        for k, v in pairs(netList) do
            local status = v.status
            if status ~= 3 then
                local ins = true
                --local moreInfo = JSON.decode(v.moreInfo)
                local moreInfo = v:GetMoreInfo()
                local model = v.model
                if isIos then
                    -- if model == ModelActivity.ADD_GROUP_ACT then
                    --     --local activityData = self:GetWebActivityDataById(v.sid)
                    --     --if activityData then
                    --     --    local config = activityData.config
                    --     ins = not string.isempty(moreInfo.iosUid)
                    --     --end
                    -- end
                end
                -- if model == ModelActivity.MONTH_ACTIVITY_ENJOY_CARD then
                --     ins = self:CheckIsShowEnjoyMonthCard(false)
                -- if model == ModelActivity.MODEL_ACTIVITY_ADVERTISING then
                --     ins = self:CheckActAdvertisingMainCityBtnShow(v)
                -- end
                if model == 18 then
                    ins = moreInfo.isNew ~= 1
                end
                if ins then
                    local uniqueJump = v.uniqueJump -- tonumber(moreInfo.uniqueJump)
                    local data = {
                        id = v.sid,
                        sort = v.sort,
                        isNet = true,
                        uniqueJump = uniqueJump,
                        name = v.title,
                    }

                    --【Y运营活动】模板4特惠礼包新增弹窗样式（客户端&服务端） A开发需求 #2473 
                    local isCanInsert = true
                    if v.model == 4 then
                        local activityWebData = gModelActivity:GetWebActivityDataById(v.sid)

                        if activityWebData then
                            local interfaceType = activityWebData.config.interfaceType
                            isCanInsert = checknumber(interfaceType) == 0
                        else
                            local specialMainCityData = GameTable.InnerActivityFuncTypeRef[18]
                            if specialMainCityData then
                                isCanInsert = false
                            end
                        end
                    elseif v.model == ModelActivity.MODEL_ACTIVITY_TYPE_169 then
                        isCanInsert = false
                        if self:IsHasPackId(moreInfo.packId,true) then
                            isCanInsert = true
                        end
                    elseif v.model == ModelActivity.COMMON_TARGET then
                        isCanInsert = false
                        if self:IsHasPackId(moreInfo.packId,true) then
                            isCanInsert = true
                        end
                    end
                    if isCanInsert then
                        table.insert(idList, data)
                    end
                end
            end
        end
    end

    ---@type V_BIActivityFuncTypeRef[]
    local cfgList = self:GetActivityFunsByType(type)
    if cfgList then
        for k, v in pairs(cfgList) do
            local model = v.eModel
            local isOpen = true
            local specialCheckFunc = nil
            --if model == ModelActivity.REAL_NAME then
            --    isOpen = gLGameLogin:GetOpenRealName()
            --    isOpen =isOpen and not gModelPlayer:IsRealNameRewarded()
            --elseif model == ModelActivity.PHONE_BIND then
            --    isOpen = gLGameLogin:GetOpenPhoneBind()
            --    isOpen =isOpen and not gModelPlayer:IsPhoneBindRewarded()
            if model == ModelActivity.GIFT_CODE then
                isOpen = gLGameLogin:IsOpenGift()
            elseif model == ModelActivity.DREAM_SECRET then
                isOpen = self:HasActivitySix()
                specialCheckFunc = function()
                    return self:HasNewSecret()
                end
                --elseif model == ModelActivity.ACCOUNT_BIND_JA then
                --    isOpen = gLGameLogin:GetOpenBindAccount()
                --    isOpen = isOpen and not gModelPlayer:InAccoutBindingReward()
                --elseif model == ModelActivity.ATTENTION_WECHAT then
                --    local serverOpen = gLGameLogin:IsOpenFocusWeChat()
                --    if serverOpen then
                --        local ref = GameTable.BIActivityWeChatRef[1]
                --        if ref then
                --            local value = ref.value
                --            isOpen = gModelNotice:IsNoticeWeChat(value)
                --        else
                --            isOpen = false
                --        end
                --    else
                --        isOpen = false
                --    end
            elseif model == ModelActivity.PREPARE_MIRROR_CALL then
                isOpen = gModelCallHero:CanGetPrepareHero()
                        and gModelCallHero:GetPrepareHeroId()
                        and gLGameLogin:IsOpenPreDrawCard()
            elseif model == ModelActivity.ACCOUNT_BIND then
                if self._regionDiff then
                    isOpen = false
                    --这里判断对应分支的奖励有没有领取完成
                    local type = { 2, 3, 4 }
                    if CS.IsOSIos() then
                        table.insert(type, 5)
                    end

                    local datas = {}
                    for k, v in ipairs(type) do
                        local cfg = self:GetVerifyConfig(v)
                        if cfg then
                            table.insert(datas, cfg)
                        end
                    end

                    for _, data in ipairs(datas) do
                        local isBind = gModelActivity:IsAccountBindTarget(self._BindStr[data.refId])

                        if not isBind then
                            isOpen = true
                            break
                        else
                            --绑定了
                            local isGot = gModelPlayer:InAccoutBindingReward(data.refId)
                            if not isGot then
                                isOpen = true
                                break
                            end
                        end
                    end
                elseif gLGameLanguage:IsChinaRegion() then
                    isOpen = false
                    --- 由后台控制开关
                    if gLGameLogin:GetOpenBindAccount() then
                        if not gModelPlayer:InAccoutBindingReward() then
                            --- 绑定了但是没领取奖励，需要显示出来
                            --local isBind = gModelActivity:IsAccountBindTarget("bindMobile")
                            --if not isBind then
                            --end
                            isOpen = true
                        end
                    end
                else
                    isOpen = gLGameLogin:GetOpenBindAccount()
                    isOpen = isOpen and not gModelPlayer:InAccoutBindingReward()
                end

                if PRODUCT_G_VER and PRODUCT_G_VER > 0 then
                    isOpen = false
                end

                if isOpen then
                    if gLGameLanguage:IsAmericaRegion() then
                        --判断包 --欧美地区判断
                        local packId = self:GetPackageId()

                        if packId == 105 then
                            isOpen = false
                        end
                    end
                end

            elseif model == ModelActivity.SPECIAL_CHARGE then
                isOpen = self:CheckSpecialChargeShow(v)
            end

            local functionId = v.functionOpenRefId
            local isShow = gModelFunctionOpen:CheckIsShow(functionId)
            if isOpen and isShow then
                local data = {
                    id = v.refId,
                    sort = v.sort,
                    isNet = false,
                    uniqueJump = v.uniqueJump,
                    redPoint = v.redPoint,
                    name = ccLngText(v.name),
                    specialCheckFunc = specialCheckFunc,
                }
                table.insert(idList, data)
            end
        end

    end

    table.sort(idList, function(a, b)
        return a.sort < b.sort
    end)

    return idList
end

