function ModelActivity:GetActivityListByModelId(model, task)
    if not self._activityListByModel then
        return false
    end
    local activityList = self._activityListByModel[model]
    if not activityList then
        return false
    end
    local activity = {}
    for k, v in pairs(activityList) do
        if v.status == 1 and v.endTime - GetTimestamp() > 0 then
            table.insert(activity, v)
        end
    end

    if #activity > 0 then
        for i, v in ipairs(activity) do
            --local moreInfo = JSON.decode(v.moreInfo)
            local moreInfo = v:GetMoreInfo()
            local needTask = moreInfo[task]
            if needTask then
                return needTask, v.icon, v.title
            end
        end
    end

    return false
end

