    if not modelId then
        return {}
    end

    if not self._activityListByModel then
        return {}
    end
    local activityDataList = {}
    local list = self._activityListByModel[modelId]
    if not list then
        return {}
    end
    -- 获取对应模块还在开启的活动数
    for k, v in pairs(list) do
        if status then
            if status == v.status then
                table.insert(activityDataList, v)
            end
        else
            if v.status ~= ModelActivity.STATUS_NO_SHOW then
                table.insert(activityDataList, v)
            end
        end
    end

    return activityDataList
end

