---更新在线奖励时间开始记时时间
function ModelActivity:UpdateOnlineRewardData(sid)
    local pages = self._activityPageKeyList[sid]
    if not pages then
        return
    end
    local page = pages[1]
    if not page then
        return
    end
    local onlineRewardMap = self._onlineRewardMap
    if not onlineRewardMap then
        onlineRewardMap = {}
        self._onlineRewardMap = onlineRewardMap
    end
    local onlineData = onlineRewardMap[sid]
    if not onlineData then
        onlineData = { sid = sid }
        onlineRewardMap[sid] = onlineData
    end
    local time = Time.RawUnityEngineTime.realtimeSinceStartup
    local curTime = math.ceil(time)
    onlineData.time = curTime
    local entry = page.entry
    local curIndex = 0
    local curEntry = nil
    local goal = nil
    local schedule = nil
    local status
    for i, v in ipairs(entry) do
        local goalData = v.goalData
        status = goalData.status
        if status ~= 2 then
            curIndex = i
            curEntry = v
            local schedules = goalData.schedules[1]
            goal = tonumber(schedules.goal)
            schedule = tonumber(schedules.schedule)
            break
        end
    end
    onlineData.curEntry = curEntry
    onlineData.goal = goal
    onlineData.schedule = schedule
    onlineData.curIndex = curIndex
    onlineData.status = status
    onlineData.nextTime = time + 2
    onlineData.isReqing = false
end

