function ModelActivity:GetMainCityActivityList()
    local lists = self:GetBIActivityFuncTypeRefList()
    local playerLv = gModelPlayer:GetPlayerLv()

    local permanentIcon = gModelNormalActivity:GetBIActivityConfigRefByKey("permanentIcon")
    local showPPrivilegeState = self:CheckPermanentPrivilege()

    local list = {}
    for i, v in ipairs(lists) do
        if playerLv < v.limitLv and v.type == 4 then
            local funcId = v.functionOpenRefId
            local isOpen = gModelFunctionOpen:CheckIsOpened(funcId, false)
            if (isOpen) then
                local fixedDateOpen = self:CheckFixedOpenDayList(funcId)
                if (not fixedDateOpen) then
                    isOpen = false
                end
            else
                --- 通过 CheckSpecialChargeShow 函数判断
                if v.eModel == ModelActivity.SPECIAL_CHARGE then
                    isOpen = true
                end
            end
            if isOpen then

                local iconEffect
                local isModelOpen = true
                if v.eModel == ModelActivity.DREAM_SCHOOL and LPlayerPrefs.dreamSchoolBEff == "true" then
                    --iconEffect = "fx_ui_tubiaorukou"
                elseif v.eModel == ModelActivity.BUILTIN_ACTIVITY_10002 then
                    local time = gModelBackflow:GetResidueTime()
                    isModelOpen = time > 0
                    --elseif v.eModel == ModelActivity.ATTENTION_WECHAT then
                    --    local serverOpen = gLGameLogin:IsOpenFocusWeChat()
                    --    if not serverOpen then
                    --        isModelOpen = false
                    --    else
                    --        local ref = GameTable.BIActivityWeChatRef[1]
                    --        if ref then
                    --            local value = ref.value
                    --            isModelOpen = gModelNotice:IsNoticeWeChat(value)
                    --        else
                    --            isModelOpen = false
                    --        end
                    --    end
                elseif v.eModel == ModelActivity.PRIVILEGE_SHOP then
                    if showPPrivilegeState ~= 0 then
                        isModelOpen = false
                    end
                elseif v.eModel == ModelActivity.PERMANENT_PRIVILEGE then
                    if showPPrivilegeState ~= 1 then
                        isModelOpen = false
                    end
                    --elseif v.eModel == ModelActivity.ACCOUNT_BIND_JA then
                    --    isModelOpen = gLGameLogin:GetOpenBindAccount()
                    --    isModelOpen =isModelOpen and not gModelPlayer:InAccoutBindingReward()
                elseif v.eModel == ModelActivity.PREPARE_MIRROR_CALL then
                    isModelOpen = gModelCallHero:CanGetPrepareHero()
                            and gModelCallHero:GetPrepareHeroId()
                            and gLGameLogin:IsOpenPreDrawCard()
                elseif v.eModel == ModelActivity.SPECIAL_CHARGE then
                    isModelOpen = self:CheckSpecialChargeShow(v)
                elseif v.eModel == ModelActivity.MODEL_ACTIVITY_TYPE_10003 then
                    isModelOpen = gModelQuest:CheckIntiveFriendOpen()
                elseif v.eModel == ModelActivity.MODEL_ACTIVITY_TYPE_10005 then
                    isModelOpen = false
                    if CS.IsWebGL() and (LWxHelper.IsDouYinPlatform() or LWxHelper.IsBiliPlatform()) then
                        -- IOS需要一直显示
                        if CS.IsWebGL() and LWxHelper.IsInIos() then
                            isModelOpen = true
                        else
                            -- 添加桌面并领取奖励后，UI图标入口消失；手机桌面删掉快捷方式，重新登录后，UI入口重新显示，但添加后无法再次获取奖励
                            if not gModelPlayer:InAccoutBindingReward(8) then
                                --- 未领取奖励显示入口
                                isModelOpen = true
                            elseif not gLSdkImpl:CallMethod(LSdkMethod.CheckIsExistShortCut) then
                                isModelOpen = true
                            end
                        end
                    end
                elseif v.eModel == ModelActivity.MODEL_ACTIVITY_TYPE_10009 then
                    isModelOpen = false
                    if CS.IsWebGL() and LWxHelper.IsDouYinPlatform() then
                        local isGet = gModelPlayer:InAccoutBindingReward(ModelSubscriber.TT_SUBSCRIBER_FEED)
                        --local isSubscriber = gLSdkImpl:CallMethod(LSdkMethod.CheckIsExistShortCut)
                        if not isGet then
                            --- 未领取奖励显示入口
                            isModelOpen = true
                        end
                    end
                end
                if isModelOpen then
                    local data = {
                        startTime = 0,
                        sort = v.sort,
                        funcId = funcId,
                        showSceneIcon = v.icon,
                        model = v.eModel,
                        title = ccLngText(v.name),
                        sid = v.refId,
                        iconEffect = iconEffect,
                        redPoint = v.redPoint,
                        showCommonEffect = v.eff
                    }
                    table.insert(list, data)
                    data.GetMoreInfo = function()
                        return nil
                    end
                end
            end
        end
    end
    local gifts = gModelPopupGift:GetSpecialGiftList()--添加特殊弹窗礼包
    for i, v in pairs(gifts) do
        local giftlist = gModelPopupGift:GetSpecialGiftListByKey(i)
        local giftItem = giftlist[1]
        if giftItem then
            local data = {
                startTime = 1,
                sort = 999999,
                funcId = 10404000,
                showSceneIcon = giftItem.ref.icon,
                model = ModelActivity.GIFT_SPECIAIPOP,
                title = ccLngText(giftItem.ref.giftName),
                sid = giftItem.id,
                showGroup = i,
            }
            table.insert(list, data)
        end
    end
    return list
end

---@param ref V_BIActivityFuncTypeRef
--- 三方充值是否显示  ModelActivity.SPECIAL_CHARGE = 9990
function ModelActivity:CheckSpecialChargeShow(ref)
    if gLGameLanguage:IsJapanRegion() then
        --- DMM 不显示入口
        local isDmm = gLSdkImpl:CallMethod(LSdkMethod.IsDMMPlatform)
        if isDmm then return false end

        if CS.IsWebGL() then
            --- H5版本不需要判断条件，直接显示
            return true
        else
            local isOpen = false
            local functionOpenRefId = ref and ref.functionOpenRefId
            if functionOpenRefId and functionOpenRefId > 0 then
                --- 后续改成配置功能开启id判断
                isOpen = gModelFunctionOpen:CheckIsShow(functionOpenRefId)
            else
                --- 原本需求（玩家累充满9.99美元 及 角色达到30级时显示该入口），防止配置功能id问题导致判断出错
                isOpen = gModelPlayer.chargeMoney >= 9.99 and gModelPlayer:GetPlayerLv() >= 30
            end
            if not isOpen then return false end

            local platform = gLSdkImpl:CallMethod(LSdkMethod.GetSdkInfo,"platform")
            if string.isempty(platform) then
                if LOG_INFO_ENABLED then
                    printInfoNR2("第三方充值","通过 SDK 获取平台为空")
                end
                return false
            end
            if platform == "Huawei" or platform == "qooapp" then
                return false
            end
            return true
        end
    else
        return gLSdkImpl:CallMethod(LSdkMethod.IsOfficialPaymentSupported)
    end
end

function ModelActivity:GetFixedOpenFunc(refId)
    local fixedOpenFuncList = {
        -- [10307000] = {
        --     funcOpenDate = gModelNaturalPartner:GetFuncOpenDate(),【G公共支持】删除本命英雄功能
        -- }
    }
    return fixedOpenFuncList[refId]
end
function ModelActivity:CheckFixedOpenDayList(refId)
    local fixedOpenFuncData = self:GetFixedOpenFunc(refId)
    if (fixedOpenFuncData) then
        local funcOpenDate = fixedOpenFuncData.funcOpenDate.serverTime
        local openDateStr = string.split(funcOpenDate, "-")
        local openTimeStamp = os.time({ day = openDateStr[3], month = openDateStr[2], year = openDateStr[1], hour = 0, minute = 0, second = 0 })
        local funcCloseDate = fixedOpenFuncData.funcOpenDate.close
        local curTime = gLGameLogin:GetGameOpenTime() / 1000
        local checkServerClose = true
        if (funcCloseDate and funcCloseDate > 0) then
            local serverOpenDay = gLGameLogin:GetServerOpenDay()
            checkServerClose = serverOpenDay >= funcCloseDate
        end
        --printInfoNR("-------funcCloseDate-----",funcCloseDate,gLGameLogin:GetServerOpenDay(),checkServerClose)
        self:ClearTimerBySpecialRefId(refId .. "open")
        local isOpen = curTime >= openTimeStamp and not checkServerClose
        --printInfoNR("-------curTime-----",curTime,openTimeStamp)
        if (curTime < openTimeStamp) then
            local timer = LxTimer.DelayTimeCall(function()
                self.testOpen = true
                self:ClearTimerBySpecialRefId(refId .. "open")
                FireEvent(EventNames.REFRESH_FUNCTION_STATE)
            end, openTimeStamp - curTime, true)
            self._specialTimerList[refId .. "open"] = timer
        end
        return isOpen
    end
    return true
end

