function ModelActivity:InitRecord()
    self._record = {}
    local list = {}
    local idList = LPlayerPrefs.activityOpenedList
    local strs = string.split(idList, "|")
    for k, v in ipairs(strs) do
        local temps = string.split(v, ",")
        if #temps == 2 then
            local sid = tonumber(temps[1])
            local time = tonumber(temps[2])
            local isInTime = false --有效记录
            local ref = self:GetActivityFunsById(sid)
            if ref then
                --读配置的活动
                isInTime = true
            else
                local actData = self:GetActivityBySid(sid)
                if actData and actData.startTime < time then
                    isInTime = true
                end
            end
            if isInTime then
                table.insert(list, v)
                self._record[sid] = time
            end
        end
    end

    local newStr = table.concat(list, "|")
    LPlayerPrefs.SetActivityOpenedList(newStr)

    gModelRedPoint:RefreshAllActTypeRed()
end

function ModelActivity:AddRecord(sid, time, isNet)
    if self._record[sid] then
        return
    end
    self._record[sid] = time
    local recordStr = LPlayerPrefs.activityOpenedList
    local str = string.format("%s,%s", sid, time)
    local newStr = recordStr .. "|" .. str
    LPlayerPrefs.SetActivityOpenedList(newStr)

    self:RefreshActTypeRed({ id = sid, isNet = isNet })
end

function ModelActivity:GetVerifyConfig(type)
    return GameTable.InnerActivityNameAndInnerndRef[type]
end

function ModelActivity:ParseConfig()
    local t = {}
    for k, v in pairs(GameTable.InnerActivityTypeRef) do
        table.insert(t, v)
    end
    table.sort(t, function(a, b)
        return a.sort < b.sort
    end)

    self._activityTypes = t

    self._activityFuns = {}
    for k, v in pairs(GameTable.InnerActivityFuncTypeRef) do
        local type = v.type
        local list = self._activityFuns[type]
        if not list then
            list = {}
            self._activityFuns[type] = list
        end
        table.insert(list, v)
    end

    for k, v in pairs(self._activityFuns) do
        table.sort(v, function(a, b)
            return a.sort < b.sort
        end)
    end

end

function ModelActivity:SetSize(trans, str)
    if string.isempty(str) or not trans then
        return
    end
    local rectTran = trans:GetComponent(typeOfRectTransform)
    rectTran = not rectTran and trans:AddComponent(typeOfRectTransform) or rectTran
    local strs = string.split(str, ",")
    if #strs >= 2 then
        local width = tonumber(strs[1])
        local height = tonumber(strs[2])
        local size = Vector2.New(width, height)
        rectTran.sizeDelta = size
    end
end

function ModelActivity:InitShopDatas()
    self._shopDataList = {}
    self._shopDataListBySid = {}
    local _activityListById = self:GetActivityListById()
    for k, v in pairs(_activityListById) do
        if v.status ~= 3 then
            if v.shopId and v.shopId > 0 then
                local shopData = {
                    sid = k,
                    pageId = v.shopId,
                    sort = v.sort,
                    name = v.title,
                    startTime = v.startTime,
                    showEndTime = v.showEndTime,
                    model = v.model,
                    status = v.status,
                    uniqueJump = v.uniqueJump,

                }
                table.insert(self._shopDataList, shopData)
                self._shopDataListBySid[v.sid] = shopData
            end
        end
    end

    table.sort(self._shopDataList, function(a, b)
        return a.startTime < b.startTime
    end)
end

