function ModelActivity:GetQuickExtraHour()
    local cfg = GameTable.InnerActivityPrivilegeDataRef[ModelActivity.PRIVILEGE_QUICK]
    if not cfg then
        return 0
    end
    local effect = cfg.effectReward
    if not string.isempty(effect) then
        local strs = string.split(effect, ',')
        --local effectIds = {}
        for k, v in ipairs(strs) do
            local id = tostring(v)
            if id then
                local cfg = gModelGeneral:GetSysEffectRef(id)
                if cfg then
                    local type = cfg.effectType
                    if type == 3 then
                        local hour = cfg.effectValue
                        return tonumber(hour)
                    end
                end
            end
        end
    end
    return 0
end

function ModelActivity:ExistActivity(modelId, uniqueJump)
    if not self._activityListByModel then
        return false
    end
    local list = self._activityListByModel[modelId]
    if not list then
        return false
    end
    for k, v in ipairs(list) do

        if v.status == 1 then
            if uniqueJump then
                if v.uniqueJump == uniqueJump then
                    return true
                end
            else
                return true
            end
        end
    end
    return false
end

