function ModelActivity:GetPackIdListByModel(model, actModelList)
    if not model then
        return {}
    end
    actModelList = actModelList or self:GetActivityDataByModelId(model)
    local packIdList = {}
    local moreInfo, packId, tPackIdList
    for i, v in ipairs(actModelList) do
        --moreInfo = JSON.decode(v.moreInfo)
        moreInfo = v:GetMoreInfo()
        packId = moreInfo.packId
        if not string.isempty(packId) then
            tPackIdList = string.split(packId, ",")
            for idx, val in ipairs(tPackIdList) do
                val = tonumber(val)
                packIdList[val] = val
            end
        end
    end
    return packIdList
end

