function ModelActivity:CheckModelIsShow(model, sid)
    local show = false
    if not model then
        return show
    end
    local packageId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId) or "0"
    packageId = tonumber(packageId)
    show = packageId == 0
    if not show then
        --[[		-- 母包不显示下载有礼
				if gLGameUpdate:IsFullPart() then
					return false
				end]]
        local checkFunc = function(packId)
            local tShow = false
            if not string.isempty(packId) then
                local packIdList = string.split(packId, ",")
                for i, v in ipairs(packIdList) do
                    if tShow then
                        break
                    end
                    tShow = tonumber(v) == packageId
                end
            end
            return tShow
        end
        if sid then
            local actData = self:GetSpecialActivityBySid(model, sid)
            if actData then
                --local moreInfo = JSON.decode(actData.moreInfo)
                local moreInfo = actData:GetMoreInfo()
                show = checkFunc(moreInfo.packId)
            end
        else
            local moreInfo
            local actList = self:GetActivityDataByModelId(model)
            for i, v in ipairs(actList) do
                if show then
                    break
                end
                --moreInfo = JSON.decode(v.moreInfo)
                moreInfo = v:GetMoreInfo()
                show = checkFunc(moreInfo.packId)
            end
        end
    end
    return show
end

function ModelActivity:GetMainCitySpecialShowActs()
    local _activityListById = self:GetActivityListById()
    if not _activityListById then
        return
    end

    --local record={}
    local showList = {}
    local soleList = {}
    for k, v in pairs(_activityListById) do
        local model = v.model
        local isSole = self._soleModelList[model]
        if self:CheckActivityMainShow(v, 2) then
            --if self._uniqueMainAct[model] and record[model] then
            --else
            if model == ModelActivity.MODEL_ACTIVITY_TYPE_63 then
                if self:CheckModelIsShow(model, v.sid) then
                    table.insert(showList, v)
                end
                -- 【G公共支持】删掉小游戏功能
                -- elseif model == ModelActivity.MODEL_GAME_TYPE_DOG then
                --     if gModelLittleGames:IsMainCityShowDogAct() then
                --         table.insert(showList,v)
                --     end
                -- elseif model == ModelActivity.MODEL_GAME_TYPE_SDK_RULING then
                --     if gModelLittleGames:IsMainCityShowSdkRulingAct() then
                --         table.insert(showList,v)
                --     end
            elseif isSole then
                local list = soleList[model] or {}
                table.insert(list, v)
                soleList[model] = list
            else
                table.insert(showList, v)
            end
            --end
        end
        --record[model] = true
    end

    for i, v in pairs(soleList) do
        local list = v
        table.sort(list, function(a, b)
            return a.sid < b.sid
        end)
        table.insert(showList, list[1])
    end

    --local entrList = self:GetMainCityActivityList()
    --for i, v in ipairs(entrList) do
    --    table.insert(showList,v)
    --end

    table.sort(showList, function(a, b)
        local isAZero = a.startTime == 0 and 1 or 2
        local isBZero = b.startTime == 0 and 1 or 2
        if isAZero ~= isBZero then
            return isAZero < isBZero
        end
        if a.startTime ~= b.startTime then
            return a.startTime > b.startTime
        end

        return a.sort < b.sort
    end)

    local maxAct = 3
    local finalList = {}
    local cnt = 0
    for k, v in pairs(showList) do
        if cnt < maxAct then
            table.insert(finalList, v)
            cnt = cnt + 1
        end
    end

    return finalList
end
function ModelActivity:GetMainCityShowActs()
    local _activityListById = self:GetActivityListById()
    if not _activityListById then
        return
    end

    --local record={}
    local showList = {}
    local soleList = {}
    for k, v in pairs(_activityListById) do
        local model = v.model
        local isSole = self._soleModelList[model]
        local specialShowFunc = self._specialShowMainCityBtnActList[model]
        
        if model == 62 then
            printInfoN2("--","--")
        end 
        
        if specialShowFunc then
            if specialShowFunc(v) then
                --特殊显示主城活动按钮
                local webData = self:GetWebActivityDataById(v.sid)
                local config
                if webData then
                    config = webData.config
                end
                local data = {
                    isSpecialAct = true,
                    actData = v,
                    startTime = v.startTime,
                    sort = v.sort,
                    specialShowSceneIcon = config and config.mainEntryIcon or v.showSceneIcon,
                    specialShowTitle = config and config.mainEntryName or v.title,
                }
                table.insert(showList, data)
            end
        else
            if self:CheckActivityMainShow(v) then
                --if self._uniqueMainAct[model] and record[model] then
                --else
                if model == ModelActivity.MODEL_ACTIVITY_TYPE_63 then
                    if self:CheckModelIsShow(model, v.sid) then
                        table.insert(showList, v)
                    end
                elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_103 then
                    local info = v:GetMoreInfo()
                    if self:IsHasPackId(info.packId, true) then
                        table.insert(showList, v)
                    end
                elseif model == ModelActivity.QUESTIONNAIRE then
                    local info = v:GetMoreInfo()
                    if self:IsHasPackId(info.packId, true) then
                        table.insert(showList, v)
                    end
                elseif model == ModelActivity.MODEL_WONDERLAND_SEVEN_DAY and gLGameLanguage:IsKoreaRegion() then
                    --对韩国地区，做特殊处理，显示在最右边
                    v.mainCityLeftIndex = 1
                    table.insert(showList, v)
                elseif isSole then
                    local list = soleList[model] or {}
                    table.insert(list, v)
                    soleList[model] = list
                    -- elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_4110 then
                    --     local moreInfo = JSON.decode(v.moreInfo)
                    --     v['iconEffect'] = "fx_shouchong_b"
                    --     if not moreInfo or moreInfo.isShow == 1 then
                    --         table.insert(showList, v)
                    --     end
                elseif model == ModelActivity.DISCOUNTS_SKIN then
                    --local moreInfo = v.moreInfo
                    --local info = JSON.decode(moreInfo)
                    local info = v:GetMoreInfo()
                    local allBuyHide = info.allBuyHide or 0
                    local buyAll = info.buyAll or 0
                    if string.isempty(allBuyHide) then
                        table.insert(showList, v)
                    elseif buyAll ~= 1 or allBuyHide ~= 1 then
                        table.insert(showList, v)
                    end
                    -- elseif model==ModelActivity.MODEL_ACTIVITY_TYPE_4108 then
                    --     v['iconEffect'] = "fx_shouchong_b"
                    --     table.insert(showList,v)
                elseif model == ModelActivity.MODEL_PASSE then
                    --local moreInfo = JSON.decode(v.moreInfo)
                    local moreInfo = v:GetMoreInfo()
                    local mainEntryShowFunctionId = moreInfo.mainEntryShowFunctionId
                    if not mainEntryShowFunctionId or mainEntryShowFunctionId <= 0
                            or not gModelFunctionOpen:CheckIsOpened(mainEntryShowFunctionId, false) then
                        --functionOpen满足后隐藏入口
                        table.insert(showList, v)
                    end

                elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_153 then
                    local webData = self:GetWebActivityDataById(v.sid)
                    local config = {}
                    if webData then
                        config = webData.config
                    end
                    
                    --B优化需求 #6724 【Y运营活动】153模板新增是否领取后消失
                    --0 买完隐藏 1 买完不隐藏
                    local isAllBuyShowCfg =  config.isShow == 1
                    -----------------------------------
                    local info = v:GetMoreInfo()
                    local pageForm = LxDataHelper.ParseItemByKeyList(config.pageForm or info.pageForm or "", { "groupId", "name", "icon" }, "|")
                    local pageFroms = {}
                    for i, p in ipairs(pageForm or {}) do
                        pageFroms[tonumber(p.groupId)] = p
                    end
                    local pageRemain = LxDataHelper.ParseItem(config.pageRemain or info.pageRemain or "", "|")
                    local temp = (GetTimestamp() - v.startTime) % 86400
                    local dayCount = math.ceil((GetTimestamp() - v.startTime) / 86400)
                    local activityDay = temp > 0 and dayCount or dayCount + 1
                    local groupId = {}

                    local tempPage = info.allBuyPage or {}
                    local allBuyPage = {}
                    for k, v in ipairs(tempPage) do
                        allBuyPage[v] = true
                    end

                    for k, p in ipairs(pageRemain or {}) do
                        groupId[p.itemType] = p.itemType
                        if p.itemId <= activityDay and (activityDay < p.itemNum or p.itemNum <= 0) then
                            local datainfo = v:Clone()


                            --在加入该组是否全部购买完 是的话就不插入 判断下groupId在不在就好了
                            local isCanInsert = true
                            for _, pageId in pairs(groupId) do

                                if allBuyPage[pageId] then
                                    --买完了
                                    isCanInsert = false
                                else
                                    isCanInsert = true
                                    break
                                end

                            end

                            if isCanInsert or isAllBuyShowCfg then
                                datainfo.groupId = groupId
                                local tempType = self:Check153Icon(allBuyPage, p.itemType)
                                --这里尝试去找一个itemType 来填充这个的值

                                datainfo.title = config.pageForm and pageFroms[tempType].name or datainfo.title
                                datainfo.showSceneIcon = pageFroms[tempType].icon
                                groupId = {}

                                table.insert(showList, datainfo)
                            end
                        end
                    end
                elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_56 then
                    --local info = JSON.decode(v.moreInfo)
                    local info = v:GetMoreInfo()
                    local limitLV = info.limitLv
                    local playerLv = gModelPlayer:GetPlayerLv()
                    if playerLv < limitLV then
                        table.insert(showList, v)
                    end
                elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_34 then
                    if self:CheckIsShowModel34(v) then
                        table.insert(showList, v)
                    end
                elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_164 then
                    local info = v:GetMoreInfo()
                    --- page1AllBuy true=分页1全买了
                    local page1AllBuy = info.page1AllBuy or false
                    ---- page2AllBuy true=已买，不需要显示
                    local page2AllBuy = not info.page2AllBuy
                    if page1AllBuy and page2AllBuy then
                        local webData = self:GetWebActivityDataById(v.sid)
                        local config = {}
                        if webData then
                            config = webData.config
                        end
                        --- 所有的购买了才可以积分弹窗 伪造一个弹窗
                        ---@type StructActivity
                        local activity = StructActivity:New()
                        activity:CreateByPb(v)
                        activity.model = ModelActivity.MODEL_ACTIVITY_TYPE_164_1
                        activity.showSceneIcon = config.mainEntryIcon or activity.icon
                        activity.title = config.mainEntryName or activity.title
                        table.insert(showList, activity)
                    end
                elseif model == ModelActivity.MODEL_ACTIVITY_TYPE_172 then
                    local info = v:GetMoreInfo()
                    if self:IsHasPackId(info.packId, true) then
                        table.insert(showList, v)
                    end
                else
                    if self:CheckShowPackId(v) then
                        table.insert(showList, v)
                    end
                end
            end
        end
        --record[model] = true
    end

    for i, v in pairs(soleList) do
        local list = v
        table.sort(list, function(a, b)
            return a.sid < b.sid
        end)
        table.insert(showList, list[1])
    end

    local entrList = self:GetMainCityActivityList()
    for i, v in ipairs(entrList) do
        table.insert(showList, v)
    end

    table.sort(showList, function(a, b)
        local mainCityLeftIndexA = a.mainCityLeftIndex or 999
        local mainCityLeftIndexB = b.mainCityLeftIndex or 999
        if mainCityLeftIndexA ~= mainCityLeftIndexB then
            return mainCityLeftIndexA < mainCityLeftIndexB
        end
        local isAZero = a.startTime == 0 and 1 or 2
        local isBZero = b.startTime == 0 and 1 or 2
        if isAZero ~= isBZero then
            return isAZero < isBZero
        end
        if a.startTime ~= b.startTime then
            return a.startTime > b.startTime
        end

        return a.sort < b.sort
    end)

    local maxAct = GameTable.InnerActivityConfigRef["mainActivityMax"]
    local finalList = {}
    local cnt = 0
    for k, v in pairs(showList) do
        if cnt < maxAct then
            table.insert(finalList, v)
            cnt = cnt + 1
        end
    end

    return finalList
end

function ModelActivity:Check153Icon(allBuyType, itemType)
    local result = 1

    if itemType > 0 then
        if not allBuyType[itemType] then
            return itemType
        else
            itemType = itemType - 1
            result = self:Check153Icon(allBuyType, itemType)
        end

    end
    return result
end

function ModelActivity:CheckActivityMainShow(actData, showType)
    local status = actData.status
    if status == ModelActivity.STATUS_NO_SHOW then
        return false
    end

    showType = showType or 1
    local endTime = actData.endTime or -1
    local isEndTime = false
    

    if endTime > 0 and endTime < GetTimestamp() and status ~= ModelActivity.STATUS_INVALID then
        isEndTime = true
    end
    local show = (actData.showScene == showType) and (not isEndTime)
    return show
    --[[    local showType = showType or 1
        local show = (actData.showScene == showType) and actData.status ~= ModelActivity.STATUS_NO_SHOW
                and (actData.endTime <= 0 or actData.endTime > GetTimestamp())
        return show]]
end

function ModelActivity:CheckPermanentPrivilege()
    local permanentIcon = gModelNormalActivity:GetBIActivityConfigRefByKey("permanentIcon")
    if permanentIcon == "0" then
        return 0--梦境特权
    end
    local isActive = self:IsPermanentPrivilegeActive()
    local nextIcon = gModelNormalActivity:GetBIActivityConfigRefByKey("nextIcon")
    if not isActive then
        return 1--终身特权
    elseif nextIcon == 0 then
        return 2--不显示
    end
    return 0--梦境特权
end

function ModelActivity:IsPermanentPrivilegeActive()
    local infos = gModelNormalActivity:GetPrivilegeGiftList()
    local giftDataRef
    for i, v in ipairs(infos) do
        local ref = gModelNormalActivity:GetBIActivityPrivilegeDataRefByRefId(v.refId)
        if ref and ref.type == 4 then
            giftDataRef = ref
        end
    end
    if not giftDataRef then
        return false
    end
    local isActive = gModelNormalActivity:IsPrivilegeActive(giftDataRef.refId)
    return isActive
end

