function ModelActivity:CommonActJump(sid)
    local actData = self:GetActivityBySid(sid)
    if not actData then
        return
    end
    local model = actData.model
    local func = self:GetShowActivityFun(model)
    if not func then
        return
    end
    func(actData)

end

function ModelActivity:ActivityJump(sid)
    local serverData = self:GetActivityBySid(sid)
    if not serverData then
        return
    end
    local cfg = gModelActivity:GetWebActivityDataById(sid)
    local type = serverData.type
    local model = serverData.model
    local toActWnd = true
    if type == ModelActivity.TYPE_FIVE then
        --[[ --9.1之后海外也同一致跳转到vip界面
        local isForeign = gLGameLanguage:IsForeignRegion()
        if not isForeign then
            toActWnd = false
        end
        ]]--

        toActWnd = false
    end
    if model == ModelActivity.COMMONRANK then
        if cfg and cfg.config.isNew == 1 then
            GF.OpenWnd("UINewAct18", { sid = sid })
            return
        end
    end
    local uniqueJump = serverData.uniqueJump
    if toActWnd then
        GF.OpenWndBottom("UIAct", { page = type, subPage = uniqueJump })
        FireEvent(EventNames.CHANGE_MAIN_BTN, LMainBtnIndexConst.ACTIVITY)
    else
        GF.OpenWndBottom("UIHuiYPay", { page = 3, subPage = uniqueJump })
    end
end
function ModelActivity:GetSidByUniqueJump(uniqueJump)
    return self._jumpMap and self._jumpMap[uniqueJump]
end

