function ModelActivity:InsertAdvertisingPhotoPopWnd(serverData)
    if GF.FindFirstWndByName("UIAdvPhotoPop") then
        return
    end

    --local hasEnterMain = gModelGeneral:GetHasEnteredCityMap()
    --if hasEnterMain then return end

    if not serverData then
        return
    end
    --local moreInfo = JSON.decode(serverData.moreInfo)
    local moreInfo = serverData:GetMoreInfo()
    local showOn = moreInfo.showOn
    if not showOn or showOn ~= 1 then
        return
    end

    local status = serverData.status
    if status ~= 1 then
        return
    end

    local sid = serverData.sid
    local localSaveData = string.split(LPlayerPrefs.advertisingPhoto, '|')
    for k, v in ipairs(localSaveData) do
        local curActData = string.split(v, '-')
        local saveSid = tonumber(curActData[1])
        if sid == saveSid then
            local jumpIndex = curActData[3]
            if jumpIndex and jumpIndex == "1" then
                --勾选已跳过
                --判断当天是否记录过
                local lastTime = curActData[4]
                if lastTime then
                    local nextDayTime = LUtil.GetNextDayTimes(tonumber(lastTime), 1)
                    if nextDayTime > GetTimestamp() then
                        return
                    end
                end
            end
        end
    end

    gModelGeneral:InsertPopActivityWnd({ uiName = "UIAdvPhotoPop", sid = sid })
end

