function ModelActivity:SaveModel84CfgInfo(activity)
    local sid = activity.sid
    local model84BossInfoList = self._model84BossInfoList
    if not model84BossInfoList then
        model84BossInfoList = {}
        self._model84BossInfoList = model84BossInfoList
    end
    local model84BossInfo = model84BossInfoList[sid]
    if not model84BossInfo then
        model84BossInfo = {}
        model84BossInfoList[sid] = model84BossInfo
    end
    --local moreInfo = JSON.decode(activity.moreInfo)
    local moreInfo = activity:GetMoreInfo()
    local boss = string.split(moreInfo.boss, "|")
    for i, v in ipairs(boss) do
        v = string.split(v, "=")
        model84BossInfo[tonumber(v[1])] = tonumber(v[2])
    end

    local model84InfoList = self._model84InfoList
    if not model84InfoList then
        model84InfoList = {}
        self._model84InfoList = model84InfoList
    end
    local model84Info = model84InfoList[sid]
    if not model84Info then
        model84Info = {}
        model84InfoList[sid] = model84Info
    end
    model84Info["activityBullet"] = moreInfo.activityBullet                     --- 位移伤害子弹特效
    model84Info["activityBullet1"] = moreInfo.activityBullet1                   --- 跑圈伤害子弹特效
    model84Info["activityHit"] = moreInfo.activityHit                           --- 位移伤害受击特效
    model84Info["activityHit1"] = moreInfo.activityHit1                         --- 跑圈伤害受击特效
    model84Info["activityHitTime"] = moreInfo.activityHitTime or 0.5            --- 位移特效显示时间
    model84Info["activityHitTime1"] = moreInfo.activityHitTime1 or 0.5          --- 跑圈特效显示时间
end

