function ModelActivity:HasActivitySix()

    if not self._activityListByType then
        return false
    end
    local activityList = self._activityListByType[ModelActivity.TYPE_SIX] or {}

    local positionList = {}
    for k, v in ipairs(activityList) do
        if v.status ~= 3 then
            table.insert(positionList, v)
        end
    end

    table.sort(positionList, function(a, b)
        return a.sort < b.sort
    end)

    if #positionList == 0 then
        return false
    end
    return true, positionList
end

function ModelActivity:HasNewSecret()
    if not self._activityListByType then
        return false
    end
    local activityList = self._activityListByType[ModelActivity.TYPE_SIX] or {}

    for k, v in ipairs(activityList) do
        if v.status ~= 3 then
            local sid = v.sid
            if self:IsActivityNew(sid, true) then
                return true
            elseif gLGameLanguage:IsForeignRegion() then
                --local data = JSON.decode(v.moreInfo)
                local data = v:GetMoreInfo()
                local receive = data.receive
                local click = data.click
                if receive == false then
                    if click == true then
                        --有奖励可领取
                        return true
                    elseif not self:IsClickActivityRed(sid) then
                        --还未领奖，且每次登录未点击
                        if gLGameLanguage:IsJapanVersion() then
                            --日本地区，不显示登录红点
                            return false
                        end

                        return true
                    end
                end
            end
        end
    end

    return false
end

