function ModelActivity:GetTowerSkipBuff(keyList)
    local activitylist = self:GetActivityDataByModelId(ModelActivity.COMMONRANK, ModelActivity.STATUS_VALID)
    if #activitylist == 0 then
        return
    end
    local list = {}
    for k, v in ipairs(activitylist) do
        --local moreInfo = JSON.decode(v.moreInfo)
        local moreInfo = v:GetMoreInfo()
        for i, v in pairs(keyList) do
            if moreInfo[v] then
                list[v] = moreInfo[v]
            end
        end
    end

    return list
end

function ModelActivity:GetActivityExtraData(actModel, keyList)
    local activitylist = self:GetActivityDataByModelId(actModel, ModelActivity.STATUS_VALID)
    if #activitylist == 0 then
        return
    end
    local list = {}
    local isFind = false
    local sid = nil
    for k, v in ipairs(activitylist) do
        --local moreInfo = JSON.decode(v.moreInfo)
        local moreInfo = v:GetMoreInfo()
        for i, v in pairs(keyList) do
            if moreInfo[v] then
                list[v] = moreInfo[v]
                isFind = true
            end
        end

        if isFind then
            sid = v.sid
            break
        end
    end

    return { sid = sid, valueList = list }
end

