function ModelActivity:GetIsOpentBySidPageId(sid, pageId)
    local str = self._isOpentList[sid] or ""
    local bool = false
    if str ~= "" then
        local arr = string.split(str, "=")
        for i, v in ipairs(arr) do
            if v == tostring(pageId) then
                bool = true
                break
            end
        end
    end
    return bool
end

function ModelActivity:SetIsOpentBySidPageId(sid, pageId)
    local str = self._isOpentList[sid] or ""
    if str == "" then
        str = tostring(pageId)
    else
        local arr = string.split(str, "=")
        local isAdd = true
        for i, v in ipairs(arr) do
            if v == tostring(pageId) then
                isAdd = false
                break
            end
        end
        if isAdd then
            str = str .. "=" .. pageId
        end
    end
    self._isOpentList[sid] = str
end

