function ModelActivity:GetPrivilegeShow1(type)
    local activityTypes = {
        -- ModelActivity.MODEL_NEWYEAR,
        -- ModelActivity.MODEL_CHN_CELEBRATE,
        -- ModelActivity.MODEL_HALLOWEEN,
        -- ModelActivity.ACTIVITY_VALENTINES_DAY,
        -- ModelActivity.MODEL_ACTIVITY_TYPE_64,
        -- ModelActivity.MODEL_ACTIVITY_TYPE_67,
        -- ModelActivity.ACTIVITY_MOTHER_DAY,
        -- ModelActivity.FAIRY_FATHER_DAY,
        ModelActivity.MODEL_ACTIVITY_TYPE_100,
    }
    local freeStrs = {
        ccClientText(19236),
        ccClientText(22209),
        ccClientText(22500),
        ccClientText(25014),
        ccClientText(25800),
        ccClientText(27203),
    }
    local tipsStrs = {
        ccClientText(19239),
        ccClientText(22213),
        ccClientText(22501),
        ccClientText(25015),
        ccClientText(25801),
        ccClientText(27204),
    }
    for i, v in ipairs(activityTypes) do
        local activitys = self:GetActivityDataByModelId(v, 1)
        if #activitys > 0 then
            local activity = activitys[1]
            local activityData = gModelActivity:GetWebActivityDataById(activity.sid)
            if not activityData then
                return false
            end
            local data = activityData.config
            local textList = {
                data.privilegeShow1Txt or freeStrs[i] or ccClientText(22209),
                data.privilegeShow4Txt or tipsStrs[i] or ccClientText(22213),
                data.privilegeShow1Call or "",
                data.privilegeShow1Tips or "",
            }
            --local moreInfo = JSON.decode(activity.moreInfo)
            local moreInfo = activity:GetMoreInfo()
            if not type then
                return true, activitys, textList
            elseif type == 1 then
                local privilegeShow1 = moreInfo.privilegeShow1
                if privilegeShow1 then
                    return true, activitys, textList
                end
            elseif type == 2 then
                local privilegeShow2 = moreInfo.privilegeShow2
                local privilegeShow3 = moreInfo.privilegeShow3
                if privilegeShow2 and privilegeShow3 then
                    return true, activitys, textList
                end
            elseif type == 3 then
                local privilegeShow4 = moreInfo.privilegeShow4
                if privilegeShow4 then
                    return true, activitys, textList
                end
            end
        end
    end
    return false, {}, {}
end

