function ModelActivity:GetActPrivilegeList(priviShowKey)
    local activityTypes = {
        ModelActivity.MODEL_ACTIVITY_TYPE_100,
        -- ModelActivity.MODEL_NEWYEAR
    }
    local dataList = {}
    for k, v in ipairs(activityTypes) do
        local acts = self:GetActivityDataByModelId(v, 1)
        for k1, v1 in ipairs(acts) do
            --local moreInfo = JSON.decode(v1.moreInfo)
            local moreInfo = v1:GetMoreInfo()
            local privilegeShow = moreInfo[priviShowKey]
            if not string.isempty(privilegeShow) then
                table.insert(dataList, tonumber(privilegeShow))
            end
        end
    end
    return dataList
end

--召唤接口                          ---活动sid，召唤条目pageId,召唤类型1单抽2十连,跳转要关闭的召唤界面名,连续召唤次数 默认10连
function ModelActivity:GetCallDataBySid(sid, pageId, callType, wndName, callLen, func)
    if self:IsActivityCallProtected() then
        return
    end

    local activityDataS = self:GetActivityBySid(sid)
    local activityDataW = self:GetWebActivityDataById(sid)
    if not activityDataS or not activityDataW then
        return
    end
    --local dataS = JSON.decode(activityDataS.moreInfo)
    local dataS = activityDataS:GetMoreInfo()
    local dataW = activityDataW.config

    local freeNum = dataS.freeNum or 0                --免费次数

    local diaLastTime = dataS.remainBuyNum          --当前钻石购买次数(转盘
    local goldTimes = dataW.goldTimes               --钻石购买的次数上限
    if dataS.callNum then
        --当前钻石购买次数(召唤
        diaLastTime = goldTimes - dataS.callNum
    end

    local diaTip = dataW.tipRefId
    local itemTip = dataW.tipRefId
    --[1] = diaTip 使用钻石提示窗; [2] = itemTip 使用道具提示窗
    local tipsList = {
        [ModelActivity.MODEL_NEWHEROCALL] = { 110023, 110022 },
        -- [ModelActivity.NEW_HERO_THEME_A] = {53005,53005},
        -- [ModelActivity.NEW_HERO_THEME_B] = {53006,53006},
        -- [ModelActivity.BAND_THEME] = {110021,53006},
        [ModelActivity.MODEL_NEWHEROCALL_DOUBLE] = { 110023, 110022 },
        --[ModelActivity.MODEL_ACTIVITY_TYPE_57] = {dataW.tipRefId,dataW.tipRefId},
        --[ModelActivity.SUMMER_DAY] = {tonumber(dataW.buyWindowTip),tonumber(dataW.buyWindowTip)},

    }
    local modelId = self:GetActivityModeIdBySid(sid)
    local tips = tipsList[modelId]
    diaTip = diaTip or (tips and tips[1] or 110032)
    itemTip = itemTip or (tips and tips[2] or 110032)


    local noChangeHero = false
    if modelId == ModelActivity.MODEL_ACTIVITY_TYPE_120 then
        local dropNum = dataS.dropNum
        local awardReplace = dataW.awardReplace or 0
        if awardReplace == 1 and dropNum and dropNum < 1 then
            noChangeHero = true
        end
    end
    local callData = {
        callMul = callLen or 10, --默认十连
        callOne = 1, --单抽
        callType = callType, --抽奖类型 1 = 单抽 or 2 = 十连
        diaLastTime = diaLastTime, --剩余钻石抽次数
        diaTip = diaTip or 110032, --使用钻石提示窗
        expendMul = {                                               --十连消耗 1 道具 2钻石
            [1] = LxDataHelper.ParseItem_3(dataW.costTen2),
            [2] = LxDataHelper.ParseItem_3(dataW.costTen1),
        },
        expendOne = {                                               --单抽消耗 1 道具 2钻石
            [1] = LxDataHelper.ParseItem_3(dataW.costOne2),
            [2] = LxDataHelper.ParseItem_3(dataW.costOne1),
        },
        freeNum = freeNum, --剩余免费次数
        goodsMul = LxDataHelper.ParseItem_3List(dataW.goodsTen), --十连购买的道具
        goodsOne = LxDataHelper.ParseItem_3List(dataW.goodsOne), --单抽购买的道具
        itemTip = itemTip or 110032, --使用道具提示窗
        pageId = pageId,
        sid = sid,
        wndName = wndName, --跳转可能需要关闭的界面
        modelId = modelId,
        noChangeHero = noChangeHero,
    }
    self:SendActivityCallReq(callData, func)
end

function ModelActivity:SendActivityCallReq(callData, callfunc)
    local callType = callData.callType
    local sid = callData.sid
    local callNum = nil
    local payType = nil
    local expend = nil
    local reward = nil
    local diaTipRefId = callData.diaTip
    local itemTipRefId = callData.itemTip
    local freeNum = callData.freeNum
    local diaLastTime = callData.diaLastTime
    local wndName = callData.wndName
    local pageId = callData.pageId or 1
    local modelId = callData.modelId
    if callType == ModelActivity.CALL_TYPE_SINGLE then
        if freeNum > 0 then
            self:_SendActivityDropGiftReq(sid,callData,function()
                self:OnActivityDropGiftReq(sid, pageId, 1, 3)
            end)
            if callfunc then
                callfunc()
            end
            return
        end
        callNum = callData.callOne
        expend = callData.expendOne
        reward = callData.goodsOne
    else
        expend = callData.expendMul
        callNum = callData.callMul
        reward = callData.goodsMul
    end
    if not expend then
        return
    end

    local actData = self:GetActivityBySid(sid)
    if not actData then
        return
    end
    --local moreInfo = JSON.decode(actData.moreInfo)
    local moreInfo = actData:GetMoreInfo()

    if moreInfo.callMaxNum then
        local callCnt = moreInfo.dropNumToday or 0
        local callLimit = moreInfo.callMaxNum
        if callCnt + callNum > callLimit then
            GF.ShowMessage(ccClientText(11626))
            return
        end
    end

    local costItem = expend[1]
    if not gModelGeneral:CheckItemEnough(costItem.itemId, costItem.itemNum) and expend[2] then
        costItem = expend[2]
    end

    if not gModelGeneral:CheckItemEnough(costItem.itemId, costItem.itemNum) then
        local isTop = callData.isTop
        local layer = LGameUI.UI_SORTLAYER_UIWND
        if isTop then
            layer = LGameUI.UI_SORTLAYER_UITOP
        end
        gModelGeneral:OpenGetWayWnd({ itemId = costItem.itemId, srcWnd = wndName }, layer)
        return
    end

    if costItem.itemId == ModelItem.ITEM_DIAMOND then
        payType = 1
        if diaLastTime and diaLastTime >= 0 and callNum > diaLastTime then
            local str = ccClientText(11680) --"钻石抽取次数不足"
            GF.ShowMessage(str)
            return
        end
    else
        payType = 2
    end


    local func = function()
        self:OnActivityDropGiftReq(sid, pageId, callNum, payType)
        if callfunc then
            callfunc()
        end
        return
    end

    local checkFunc = function()
        local actName = self:GetLngNameByActivitySid(sid)

        local award = reward[#reward]
        local cntName = modelId == 92 and ccClientText(30712) or ""
        local rewardStr = string.format("%s%s%s", award.itemNum, cntName, gModelGeneral:GetCommonItemName(award))
        --for i, v in ipairs(reward) do
        --    local str = string.format("%s%s",v.itemNum,gModelGeneral:GetCommonItemName(v))
        --    if i == 1 then
        --        rewardStr = str
        --    else
        --        rewardStr = rewardStr..","..str
        --    end
        --end
        local costStr = string.format("%s%s%s", costItem.itemNum, cntName, gModelGeneral:GetCommonItemName(costItem))
        local wndPara = nil
        if costItem.itemId == ModelItem.ITEM_DIAMOND then
            wndPara = {
                refId = diaTipRefId,
                sid = sid,
                para = { costStr, rewardStr, callNum, actName },
                func = func,
                consume = { costItem.itemNum, costItem.itemId },
                isDiamond = true
            }
        else
            wndPara = {
                refId = itemTipRefId,
                sid = sid,
                para = { costStr, rewardStr, callNum, actName },
                func = func,
            }
        end
        local isFull = gModelGeneral:IsFullHeroBag(0, nil, nil, nil, nil, wndName)
        if isFull then
            return
        end
        gModelGeneral:OpenUIOrdinTips(wndPara, true)
    end
    self:_SendActivityDropGiftReq(sid,callData,checkFunc)
end

function ModelActivity:_SendActivityDropGiftReq(sid,callData,sendReq)
    if callData.noChangeHero then
        gModelGeneral:OpenUIOrdinTips({
            refId = 110066,
            sid = sid,
            func = sendReq,
        }, true)
    else
        sendReq()
    end
end

function ModelActivity:SendActivityCallReq2(sid, pageId, callType, wndName, _lotteryEnum, callfunc)
    local model = self:GetActivityModeIdBySid(sid)
    -- if model and model == ModelActivity.MODEL_ACTIVITY_TYPE_96 and _lotteryEnum == ModelActivity.DROP_REWARD_LOTTERY then
    --     if self:IsActivityCallProtected() then
    --         return
    --     end
    -- end

    local activityDataS = self:GetActivityBySid(sid)
    local activityDataW = self:GetWebActivityDataById(sid)
    if not activityDataS or not activityDataW then
        return
    end
    --local dataS = JSON.decode(activityDataS.moreInfo)
    local dataS = activityDataS:GetMoreInfo()
    local dataW = activityDataW.config

    local freeNum = dataS.freeNum or 0                --免费次数
    local diaLastTime = dataS.remainBuyNum          --当前钻石购买次数(转盘
    local dropNumToday = dataS.usedBuyNum           --今天总掉落次数
    local goldTimes = dataW.goldTimes               --钻石购买的次数上限
    local callMaxNum = dataW.callMaxNum             --抽奖次数上限
    local costOne1, costOne2, goodsOne = dataW.costOne1, dataW.costOne2, dataW.goodsOne
    if dataS.callNum then
        --当前钻石购买次数(召唤
        diaLastTime = goldTimes - dataS.callNum
    end
    local tipRefId = dataW.tipRefId
    local tipRefId2 = dataW.tipRefId2
    local tipRefId3 = dataW.tipRefId3               --钻石购买时的tips提示

    local func = function()
        gModelActivity:OnActivitySpecialOpReq(sid, pageId, 0, 0, tostring(callType), _lotteryEnum)
        if callfunc then
            callfunc()
        end
        return
    end
    if freeNum > 0 and callType == 1 then
        if func then
            func()
        end
        return
    end
    if callMaxNum then
        local callCnt = dropNumToday or 0
        if callCnt >= callMaxNum then
            GF.ShowMessage(ccClientText(11626))
            return
        end
    end
    local _costOne1, _costOne2, _goodsOne = LxDataHelper.ParseItem_3(costOne1), LxDataHelper.ParseItem_3(costOne2), LxDataHelper.ParseItem_3List(goodsOne)
    local costItem = _costOne2
    if not gModelGeneral:CheckItemEnough(costItem.itemId, costItem.itemNum) then
        costItem = _costOne1
    end
    if not gModelGeneral:CheckItemEnough(costItem.itemId, costItem.itemNum) then
        gModelGeneral:OpenGetWayWnd({ itemId = costItem.itemId, srcWnd = wndName })
        return
    end

    local isDiamond = false
    if costItem.itemId == ModelItem.ITEM_DIAMOND then
        if diaLastTime <= 0 then
            local str = ccClientText(11680) --"钻石抽取次数不足"
            GF.ShowMessage(str)
            return
        end

        isDiamond = true
    end

    local itemId = costItem.itemId
    local needNum = costItem.itemNum
    local tipRefId = callType == 1 and tipRefId or tipRefId2
    local wndPara = {
        refId = tipRefId,
        sid = sid,
        func = func,
        consume = { needNum, itemId },
    }
    if callType == 1 then
        local costStr = string.format("%s%s", costItem.itemNum, gModelGeneral:GetCommonItemName(costItem))
        local rewardStr = ""
        if _goodsOne then
            local len = #_goodsOne
            rewardStr = string.format("%s%s", _goodsOne[len].itemNum, gModelGeneral:GetCommonItemName(_goodsOne[len]))
        end
        local actName = gModelActivity:GetLngNameByActivitySid(sid)
        wndPara = {
            refId = tipRefId,
            sid = sid,
            para = { costStr, rewardStr, actName },
            func = func,
            consume = { needNum, itemId },
        }
    else
        local own = gModelItem:GetNumByRefId(itemId)
        local enoughTime = math.floor(own / needNum)
        local limitCallNum = math.min(enoughTime, 10)
        if isDiamond then
            limitCallNum = math.min(diaLastTime, limitCallNum)
            if tipRefId3 and tipRefId3 > 0 then
                tipRefId = tipRefId3
            end

        end

        local resultNeedNum = limitCallNum * needNum
        local costStr = gModelGeneral:GetCommonItemName(costItem)
        wndPara = {
            refId = tipRefId,
            sid = sid,
            para = { costStr },
            func = func,
            consume = { resultNeedNum, itemId },
        }
    end
    local isFull = gModelGeneral:IsFullHeroBag(0, nil, nil, nil, nil, wndName)
    if isFull then
        return
    end
    gModelGeneral:OpenUIOrdinTips(wndPara, true)
end

function ModelActivity:BuyCustomGift(itemdata)

    local marketData = itemdata.entryData.MarketData
    local buyNum = marketData.personalGoal - marketData.personal

    if buyNum <= 0 then
        GF.ShowMessage(ccClientText(15511))
        return
    end

    local sid, pageId, entryId = itemdata.sid, itemdata.pageId, itemdata.entryCfg.id
    local expendType = marketData.expendType
    local buyFunc, setTextStr, itemId
    if expendType == 0 then
        buyFunc = function()
            self:OnActivityMarkeyBuyReq(sid, pageId, entryId)
        end
        setTextStr = ccClientText(11913)
    elseif expendType == 1 then
        local costItem = LxDataHelper.ParseItem_3(marketData.expend2)
        itemId = costItem.itemId
        local value = costItem.itemNum
        local costStr = string.format("%s%s", value, gModelItem:GetNameByRefId(costItem.itemId))
        buyFunc = function()
            local para = {
                refId = 110005,
                func = function()
                    if gModelGeneral:CheckItemEnough(costItem.itemId, costItem.itemNum, nil, nil, nil, costItem.itemType) then
                        local consumeDetail = gModelActivity:GetConsumeDetail({ costItem })
                        self:OnActivityMarkeyBuyReq(sid, pageId, entryId, nil, nil, consumeDetail)
                    else
                        gModelGeneral:OpenGetWayWnd({ itemId = costItem.itemId, refIdType = costItem.itemType })
                    end
                end,
                para = { costStr },
                consume = { value, itemId }
            }
            gModelGeneral:OpenUIOrdinTips(para)
        end
        setTextStr = tostring(costItem.itemNum)
    elseif expendType == 2 then
        local expendId = tonumber(marketData.expend2)
        setTextStr = gModelPay:GetShowByWelfareId(expendId)
        buyFunc = function()
            gModelPay:GiftPayCtrl(entryId, expendId, ModelPay.PAY_TYPE_ACTIVITY, nil, sid, pageId)
        end
    end

    local showItemList = {}
    for k, v in ipairs(itemdata.fixReward) do
        table.insert(showItemList, v)
    end

    for k, v in ipairs(itemdata.selReward) do
        table.insert(showItemList, v)
    end

    local wndPara = {
        title = itemdata.entryCfg.name,
        desc = string.replace(ccClientText(23803), buyNum),
        payStr = setTextStr,
        payItemId = itemId,
        payFunc = buyFunc,
        itemList = showItemList,
    }
    GF.OpenWnd("UIGiftBuyPop", wndPara)
end

function ModelActivity:FormatActGoodsList(pageData)
    local sid = pageData.sid
    local pageId = pageData.pageId

    local pageCfg = self:GetWebActivityPageData(sid, pageId)

    local dataList = {}
    if not pageCfg then
        return dataList
    end

    for k, v in ipairs(pageCfg.entries) do

        local entryData = pageData:GetEntry(v.id)
        if entryData then
            local moreInfo = JSON.decode(entryData.moreInfo)
            local hide = moreInfo and moreInfo.isShowGoods == 1
            local newGoods = moreInfo and moreInfo.newGoods == 1
            if not hide then
                local canBuy = true
                local personal = entryData.MarketData.personal
                local personalGoal = entryData.MarketData.personalGoal
                local server = entryData.MarketData.server
                local serverGoal = entryData.MarketData.serverGoal
                if personalGoal > 0 and personal >= personalGoal then
                    canBuy = false
                end

                if serverGoal > 0 and server >= serverGoal then
                    canBuy = false
                end

                local prio = canBuy and 1 or 2

                local pricestr = v.expend1
                if string.isempty(pricestr) then
                    pricestr = v.expend2
                end
                local itemList = LxDataHelper.ParseItem(pricestr) or {}
                local price = itemList[1]

                local rewardList = LxDataHelper.ParseItem(v.reward) or {}
                local reward = rewardList[1]

                local data = {
                    sid = sid,
                    pageId = pageId,
                    entryId = v.id,
                    name = v.name,
                    item = reward,
                    sort = v.sort,
                    personal = personal,
                    personalGoal = personalGoal,
                    server = server,
                    serverGoal = serverGoal,
                    price = price,
                    resetType = v.condResetType,
                    prio = prio,
                    disText = v.moreInfo,
                    unlock = v.unlock,
                    unlockTxt = v.unlockTxt,
                    newGoods = newGoods,
                    moreInfoCfg = v.moreInfo,
                }

                table.insert(dataList, data)
            end


        end

    end

    table.sort(dataList, function(a, b)
        if a.prio ~= b.prio then
            return a.prio < b.prio
        end
        return a.sort < b.sort
    end)

    return dataList
end

