function ModelActivity:CheckIsDownLoadFinish()
    local actDownLoadData = self:GetDownLoadActData()
    if not actDownLoadData then
        return
    end
    local sid = actDownLoadData.sid
    local progress = self:GetActDownloadScheduleBySid(sid)
    if progress >= 1 then
        self._sendDownLoadStatus = false
        self:DownLoadFinishSendMsg(true)
    end
end

function ModelActivity:GetDownLoadActData()
    local downloadModel = ModelActivity.MODEL_ACTIVITY_TYPE_63
    local downLoadActList = self:GetActivityDataByModelId(downloadModel)
    for i, v in ipairs(downLoadActList) do
        return v
    end
end

function ModelActivity:DownLoadFinishSendMsg(limit)
    if limit and self._sendDownLoadStatus then
        if self._sendDownLoadStatus then
            return
        end
    end
    local actDownLoadData = self:GetDownLoadActData()
    if not actDownLoadData then
        return
    end
    self._sendDownLoadStatus = true
    self:OnActivitySpecialOpReq(actDownLoadData.sid, ModelActivity.DOWNLOAD_REWARD_PAGEID, ModelActivity.DOWNLOAD_REWARD_ENTRYID, 0, nil, ModelActivity.DOWNLOAD_GIFT_OPERA)
end

function ModelActivity:IsTowerOpened(sid)
    if not self._towerOpenRecord then
        self:InitTowerOpenRecord()
    end

    local towerOpenRecord = self._towerOpenRecord

    local sidMap = towerOpenRecord.sidMap
    if not sidMap then
        sidMap = {}
        towerOpenRecord.sidMap = sidMap
    end
    return sidMap[sid] or false
end

function ModelActivity:InitTowerOpenRecord()
    local towerOpenRecord = {}

    self._towerOpenRecord = towerOpenRecord

    local sidMap = {}
    local sidList = JSON.decode(LPlayerPrefs.bossTowerFirstOpen or "")
    if sidList then
        for k, v in ipairs(sidList) do
            sidMap[v] = true
        end
    end
    towerOpenRecord.sidList = sidList or {}
    towerOpenRecord.sidMap = sidMap
end

function ModelActivity:SetTowerOpened(sid)
