function ModelActivity:SaveRedSids(_redRecordSids)
    if #_redRecordSids <= 0 then
        return
    end
    local _redSidList = self._redSidList
    if not _redSidList then
        local redSidList = LPlayerPrefs.redSidList
        local arr = string.split(redSidList, "|")
        local list = {}
        for i, v in ipairs(arr) do
            table.insert(list, tonumber(v))
        end
        _redSidList = list
        self._redSidList = list
    end
    local keyRed = {}
    for i, v in ipairs(_redSidList) do
        keyRed[v] = true
    end
    local isNew = false
    local newRedList = {}
    for i, v in ipairs(_redRecordSids) do
        local bool = keyRed[v]
        if not bool then
            isNew = true
            newRedList[v] = true
        end
    end
    self._newRedList = newRedList
    if isNew then
        FireEvent(EventNames.ON_ACTIVITY_SAVE_RED_TIPS)
    end
end

function ModelActivity:GetSaveRedBySid(sid)
    local _newRedList = self._newRedList or {}
    return _newRedList[sid]
end

function ModelActivity:SetSaveRed(sid)
    local _newRedList = self._newRedList or {}
    if not _newRedList[sid] then
        return
    end
    local _redSidList = self._redSidList
    if not _redSidList then
        return
    end
    self._newRedList[sid] = nil
    table.insert(_redSidList, sid)
    self._redSidList = _redSidList
    local redSidList = ""
    for i, v in ipairs(_redSidList) do
        if i == 1 then
            redSidList = tostring(v)
        else
            redSidList = redSidList .. "|" .. v
        end
    end
    LPlayerPrefs.SetRedSidList(redSidList)
    FireEvent(EventNames.ON_ACTIVITY_SAVE_RED_UPDATE)
end

