function ModelActivity:InitActDownloadRecord()
    local actDownloadRecord = {}
    self._actDownloadRecord = actDownloadRecord

    local actDownloadSchedule = string.split(LPlayerPrefs.actDownloadSchedule, "|")
    local sid, schedule
    for i, v in ipairs(actDownloadSchedule) do
        v = string.split(v, "=")
        sid = tonumber(v[1])
        schedule = tonumber(v[2])
        actDownloadRecord[sid] = schedule
    end
end

function ModelActivity:GetActDownloadScheduleBySid(sid)
    if not self._actDownloadRecord then
        self:InitActDownloadRecord()
    end
    local actDownloadRecord = self._actDownloadRecord
    return actDownloadRecord[sid] or 0
end

function ModelActivity:SetActDownloadSchedule(sid, schedule)
    if not sid or not schedule then
        return
    end
    if not self._actDownloadRecord then
        self:InitActDownloadRecord()
    end
    self._actDownloadRecord[sid] = schedule
    local actDownloadRecord = self._actDownloadRecord
    local str, tempStr
    for key, val in pairs(actDownloadRecord) do
        tempStr = key .. "=" .. val
        if str then
            str = str .. "|" .. tempStr
        else
            str = tempStr
        end
    end
    LPlayerPrefs.SetActDownloadSchedule(str)
end

