function ModelActivity:RecordTaskCardData(sid, cardMap)
    if not (sid and cardMap) then
        return
    end
    self:InitTaskCardData()

    self._taskCardDataMap[sid] = cardMap

    local time = GetTimestamp()
    local retStrList = {}
    for k, v in pairs(self._taskCardDataMap) do
        local strList = {}
        for k1, v1 in pairs(v) do
            if v1 then
                table.insert(strList, tostring(k))
            end
        end
        local indexStr = table.concat(strList, '-')

        local cardStr = string.format("%s=%s=%s", sid, time, indexStr)
        table.insert(retStrList, cardStr)
    end

    local retStr = table.concat(retStrList, '|')
    LPlayerPrefs.SetBandThemeTaskCards(retStr)
end

function ModelActivity:GetTaskCardData(sid)
    self:InitTaskCardData()

    local data = self._taskCardDataMap[sid]
    local isFirst = false
    if not data then
        isFirst = true
        data = {}
    end
    return data, isFirst
end

function ModelActivity:InitTaskCardData()
    local cardDataMap = self._taskCardDataMap
    if not cardDataMap then
        cardDataMap = {}
        self._taskCardDataMap = cardDataMap

        local oldList = string.split(LPlayerPrefs.bandThemeTaskCards, '|')
        for k, v in ipairs(oldList) do
            local curData = string.split(v, '=')
            local curSid = tonumber(curData[1])
            local cardList = string.split(curData[3], '-')
            local cardMap = {}
            for k1, v1 in ipairs(cardList) do
                local cardIndex = tonumber(v1)
                cardMap[cardIndex] = true
            end

            cardDataMap[curSid] = cardMap
        end
    end
end

