end

function ModelActivity:GetSelectOpenCommonReward(sid, list1, list2)
    if not sid then
        return list1, list2
    end
    local activityData = gModelActivity:GetActivityBySid(sid)
    local activityWebData = gModelActivity:GetWebActivityDataById(sid)
    if activityData and activityWebData then
        local config = activityWebData.config
        local selectOpen = config and tonumber(config.selectOpen) or ModelActivity.TYPE_SELECTOPEN_0
        if selectOpen == ModelActivity.TYPE_SELECTOPEN_1 then
            --local moreInfo = JSON.decode(activityData.moreInfo)
            local moreInfo = activityData:GetMoreInfo()
            local select = tonumber(moreInfo.select) or 0
            if select > 0 then
                local needChangeItem
                local heroRefId
                local selectHero = string.split(config.selectHero, "|")
                for i, v in ipairs(selectHero) do
                    v = string.split(v, "=")
                    heroRefId = tonumber(v[1])
                    if heroRefId == select then
                        needChangeItem = tonumber(v[2])
                        break
                    end
                end
                if needChangeItem then
                    local transitionItem = tonumber(config.transitionItem)
                    if transitionItem and transitionItem > 0 then
                        list1 = list1 or {}
                        for i, v in ipairs(list1) do
                            if v.itemId == transitionItem then
                                v.itemId = transitionItem
                            end
                        end
                        list2 = list2 or {}
                        for i, v in ipairs(list2) do
                            if v.itemId == transitionItem then
                                v.itemId = needChangeItem
                            end
                        end
                    end
                end
            end
        end
    end
    return list1, list2
end

