function ModelActivity:TryInsertActivityGuide(needGuideSidList)
    if table.isempty(needGuideSidList) then
        return
    end

    local guideMainActivity = string.split(LPlayerPrefs.guideMainActivity, '|')
    local localSidDataList = {}
    for k, v in ipairs(guideMainActivity) do
        local data = string.split(v, "=")
        local sid = tonumber(data[1])
        local state = tonumber(data[2])
        localSidDataList[sid] = {
            state = state,
            curHaveAct = false,
        }
    end

    local curNeedGuideSid
    for k, v in ipairs(needGuideSidList) do
        local canGuide = false
        if localSidDataList[v] then
            local state = localSidDataList[v].state
            if state == 0 then
                canGuide = true
            end

            localSidDataList[v].curHaveAct = true
        else
            localSidDataList[v] = {
                state = 0,
                curHaveAct = true,
            }

            canGuide = true
        end

        if not curNeedGuideSid and canGuide then
            curNeedGuideSid = v
        end
    end

    local str
    for k, v in pairs(localSidDataList) do
        if v.curHaveAct then
            local state = v.state
            if not str then
                str = k .. "=" .. state
            else
                str = str .. '|' .. k .. "=" .. state
            end
        end
    end

    if not str then
        str = ""
    end

    LPlayerPrefs.SetGuideMainActivity(str)

    if curNeedGuideSid then
        local activity = self:GetActivityBySid(curNeedGuideSid)
        local _sid = activity.sid
        gModelGeneral:InsertPopActivityWnd({ uiName = "UIGueTip", sid = _sid, wndType = 6 })
    end
end

function ModelActivity:ResetGuideMainActivity(sid)
    local guideMainActivity = string.split(LPlayerPrefs.guideMainActivity, '|')
    local localSidDataList = {}
    local hadData = false
    for k, v in ipairs(guideMainActivity) do
        local data = string.split(v, "=")
        local curSid = tonumber(data[1])
        if curSid == sid then
            localSidDataList[curSid] = 1
            hadData = true
        else
            local state = tonumber(data[2])
            localSidDataList[curSid] = state
        end
    end

    if not hadData then
        localSidDataList[sid] = 1
    end

    local str
    for k, v in pairs(localSidDataList) do
        if not str then
            str = k .. "=" .. v
        else
            str = str .. '|' .. k .. "=" .. v
        end
    end

    if not str then
        str = ""
    end

    LPlayerPrefs.SetGuideMainActivity(str)
end

