function ModelActivity:GetCreateProjectQuestionLinkExtraStr(sid)
    local playerId = gLGameLogin:GetLoginIdentityId() -- gLGameLogin:GetPlayerId()
    local serverId = gLGameLogin:GetServerId()

    if gLGameLanguage:IsKoreaRegion() then

        local linkFirst = "&gameCode=cocmw"
        local linkParam = gLSdkImpl:CallMethod(LSdkMethod.GetSdkLinkParam) or ""
        local linkStr = linkFirst .. linkParam

        local linkParamFormat = "&sojumpparm=%s%%7C%s%%7C%s"
        local rewardLink = string.replace(linkParamFormat, playerId, serverId, sid)

        return linkStr .. rewardLink
    else
        --url后插入 ?sojumpparm=玩家id|服务器id|活动refId
        local playerId = gLGameLogin:GetLoginIdentityId() -- gLGameLogin:GetPlayerId()
        local serverId = gLGameLogin:GetServerId()
        local linkParamFormat = "?sojumpparm=%s|%s|%s"
        local linkStr = string.replace(linkParamFormat, playerId, serverId, sid)
        local resLink = string.urlencode(linkStr)
        return resLink
    end
end

