function ModelActivity:GetConsumeDetail(expend, itemCnt)
    local list = expend
    if (not list or #list <= 0) then
        return
    end
    local consumeDetail
    local consumeDetailList = {}
    local itemCntNum = itemCnt or 1
    for i, v in pairs(list) do
        local expendRewardType = v.itemType
        local expendId = v.itemId
        local expendNum = v.itemNum * itemCntNum
        if (expendRewardType == 2) then
            local heroIdList = gModelHeroExtra:GetBeCapableOfSellHeroIdList(expendId, expendNum)
            local detailStr = table.concat(heroIdList, ",")
            detailStr = "2=" .. detailStr
            table.insert(consumeDetailList, detailStr)
        end
    end
    consumeDetail = table.concat(consumeDetailList, ";")
    return consumeDetail
end


