function ModelActivity:GetPlotWeightCfg()
    -- local actData =self:GetSpecialActivity(ModelActivity.MODEL_RANDOM_PLOT)
    local actData = nil
    if not actData then
        return
    end

    --local moreInfo = JSON.decode(actData.moreInfo)
    local moreInfo = actData:GetMoreInfo()
    if not self:IsPackIdAvailable(moreInfo.packId) then
        return
    end

    local strs = string.split(moreInfo.packRandomGuide, ",")
    local dataList = {}
    for k, v in ipairs(strs) do
        local temps = string.split(v, "=")
        local data = {
            refId = tonumber(temps[2]),
            weight = tonumber(temps[1])

        }
        table.insert(dataList, data)
    end

    table.sort(dataList, function(a, b)
        return a.refId < b.refId
    end)

    return dataList
end

function ModelActivity:IsHasPackId(packId, defaultVal)
    if string.isempty(packId) then
        return defaultVal
    end

    local strs = string.split(packId, ";")
    local selfpackId = tostring(self:GetPackageId())
    for k, v in ipairs(strs) do
        if v == selfpackId then
            return true
        end
    end

    return false
end

function ModelActivity:IsPackIdAvailable(packId)
    local strs = string.split(packId, ",")
    local selfpackId = tostring(self:GetPackageId())
    for k, v in ipairs(strs) do
        if v == selfpackId then
            return true
        end
    end
    return false
end

