function ModelActivity:GetMainCitySpecialAct()
    --if not gLGameLanguage:IsJapanRegion() then return end

    local funcType19Ref = self:GetActivityFunsById(19)
    if not funcType19Ref then return end

    local isOpen = gModelFunctionOpen:CheckIsOpened(funcType19Ref.uniqueJump)
    if not isOpen then return end

    local lv = gModelPlayer:GetPlayerLv()
    if lv > checknumber(funcType19Ref.limitLv) then return end

    local model = funcType19Ref.eModel
    if not model or model < 1 then return end

    local modelDatas = self:GetActivityDataByModelId(model)
    if not modelDatas or #modelDatas < 1 then return end

    local list = {}
    for i,v in ipairs(modelDatas) do
        table.insert(list,{
            isSpecialAct = true,
            isSpecialMainCityAct = true,
            refData = funcType19Ref,
            model = model,
            actData = v,
        })
    end

    return list
end

